        use crate::platform::{PlatformErrorKind, desktop::DesktopActions};

        let result = RealDesktopActions::new().open_url("https://example.invalid/cmt");

        assert_eq!(
            result.failure_kind(),
            Some(PlatformErrorKind::UnsupportedPlatform)
