        (
            WorkerTaskStatus::Completed,
            WorkerPayload::ArchivePatcher(
                ArchivePatcherWorkerPayload::PatchCompleted { .. }
                    | ArchivePatcherWorkerPayload::RestoreCompleted { .. },
            ),
        )
    )
}

