fn bind_tools_callbacks(
    app: &MainWindow,
    downgrader_window: &DowngraderWindow,
    archive_patcher_window: &ArchivePatcherWindow,
    controller: Arc<Mutex<ToolsController>>,
    downgrader_controller: Arc<Mutex<DowngraderController>>,
